import React, { useState, useEffect } from "react";
import axios from "axios";
import DeleteButton from "./DeleteButton";
import "./ExperienceAdmin.css";

const API = "http://localhost:5064/api";

interface Experience {
    experienceId: number;
    titre: string;
    description: string;
    entreprises: string;
    dateDebut: string;
    dateFin: string | null;
    competences: string[];
}

interface NewExperience {
    titre: string;
    description: string;
    entreprises: string;
    dateDebut: string;
    dateFin: string | null;
    competences: string;
}

export default function ExperienceAdmin() {
    const [experiences, setExperiences] = useState<Experience[]>([]);
    const [newExperience, setNewExperience] = useState<NewExperience>({
        titre: "",
        description: "",
        entreprises: "",
        dateDebut: "",
        dateFin: "",
        competences: "",
    });

    useEffect(() => {
        fetchExperiences().catch();
    }, []);

    const fetchExperiences = async () => {
        try {
            const response = await axios.get<Experience[]>(`${API}/experience-pro`);
            setExperiences(response.data);
        } catch (error) {
            console.log("Erreur lors de la récupération des expériences :", error);
        }
    };

    const handleAdd = async () => {
        if (newExperience.titre && newExperience.description && newExperience.dateDebut) {
            try {
                const competencesArray = newExperience.competences.split(",").map((comp) => comp.trim());
                const response = await axios.post(`${API}/experience-pro`, {
                    ...newExperience,
                    competences: competencesArray,
                });
                setExperiences([...experiences, response.data]);
                setNewExperience({
                    titre: "",
                    description: "",
                    entreprises: "",
                    dateDebut: "",
                    dateFin: "",
                    competences: "",
                });
            } catch (error) {
                console.log("Erreur lors de l'ajout de l'expérience :", error);
            }
        }
    };

    return (
        <div className="ExperienceAdminContainer">
            <h2>Gestion des Expériences</h2>

            <div className="AddExperienceForm">
                <input
                    type="text"
                    placeholder="Titre"
                    value={newExperience.titre}
                    onChange={(e) => setNewExperience({ ...newExperience, titre: e.target.value })}
                />
                <input
                    type="text"
                    placeholder="Description"
                    value={newExperience.description}
                    onChange={(e) => setNewExperience({ ...newExperience, description: e.target.value })}
                />
                <input
                    type="text"
                    placeholder="Entreprise"
                    value={newExperience.entreprises}
                    onChange={(e) => setNewExperience({ ...newExperience, entreprises: e.target.value })}
                />
                <input
                    type="date"
                    placeholder="Date de début"
                    value={newExperience.dateDebut}
                    onChange={(e) => setNewExperience({ ...newExperience, dateDebut: e.target.value })}
                />
                <input
                    type="date"
                    placeholder="Date de fin"
                    value={newExperience.dateFin || ""}
                    onChange={(e) => setNewExperience({ ...newExperience, dateFin: e.target.value || null })}
                />
                <input
                    type="text"
                    placeholder="Compétences (séparées par des virgules)"
                    value={newExperience.competences}
                    onChange={(e) => setNewExperience({ ...newExperience, competences: e.target.value })}
                />
                <button onClick={handleAdd}>Ajouter</button>
            </div>

            <ul className="ExperienceList">
                {experiences.map((experience) => (
                    <li key={experience.experienceId} className="ExperienceItem">
                        <h3>{experience.titre}</h3>
                        <p>{experience.description}</p>
                        <p>Entreprise: {experience.entreprises}</p>
                        <DeleteButton
                            id={experience.experienceId}
                            apiEndpoint="experience-pro"
                            onDeleteSuccess={fetchExperiences}
                        />
                    </li>
                ))}
            </ul>
        </div>
    );
}
